var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"침식 코어의 위치에 대한 계시가 내려왔습니다.","JPN":"侵食コアの位置に関する啓示が降りました。","ENG":"I've received a new revelation about the location of the Corruption Core.","TWN":"侵蝕核心位置的啟示降臨了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"수호령께서 적은 능선 너머의 유적지에 자리 잡고 있다고 속삭여 주셨습니다.","JPN":"守護霊様が「稜線の向こう側の遺跡地帯に侵食コアがある」とささやいてくださいました。","ENG":"My guardian spirit whispered to me that the enemy lies in the ruins beyond the ridgeline.","TWN":"守護神告訴我，敵人在越過山脊後的遺跡裡。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......이젠 태클 걸기도 지치는 것 같아.","JPN":"……もうツッコミを入れるのも疲れたよ。","ENG":"...I'm getting tired of asking.","TWN":"……我已經不想吐槽妳了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"카드점에서 수호령이라니...... 커버 범위가 꽤 넓군.","JPN":"カード占いから守護霊まで、幅広く対応してるんだな。","ENG":"First tarot cards, and now guardian spirits...? Your practice is much more eclectic than I thought.","TWN":"又是塔羅牌又是守護神……妳涉獵的範圍還真廣啊。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"아무튼, 유적지라고?","JPN":"それで、遺跡地帯だと？","ENG":"Anyway, you said it's in the ruins?","TWN":"算了，妳說是遺跡對吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"유적지가 뭐지?","JPN":"遺跡地帯って何？","ENG":"Ruins? What's that?","TWN":"遺跡是指什麼？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이면세계라고 해서 황무지만 펼쳐져 있는 건 아니야. ","JPN":"カウンターサイドだからといって、荒地ばかりとは限らない。 ","ENG":"The Counterside isn't just a vast wasteland. ","TWN":"異界雖然荒蕪，但不代表它就是一片單調的景色。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"뭐, 여러 가지 지형들이 다양하게 있지만.......","JPN":"様々な地形が広がっているが……","ENG":"There is a wide range of terrain here...","TWN":"它其中也包含了各種地形。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"개중에 제일 흔하게 볼 수 있는 게 바로 유적지다.","JPN":"そのなかでも、一番よく見られるのが遺跡地帯だ。","ENG":"But the most common geographical feature would be ruins.","TWN":"而最常見的地形就是遺跡。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"돌아다니다 보면 생각보다 재미있는 곳이 많아요.","JPN":"見て回ると、思ったよりも面白い場所がたくさんありますよ。","ENG":"There's a lot of interesting spots if you look around.","TWN":"去逛過之後，妳就會發現那裡比妳想像得還要有趣。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"참 아이러니하지 않나요?","JPN":"なんとも皮肉ですよね。","ENG":"Ironic, isn't it?","TWN":"這不是很諷刺嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이런 외계 행성 같은 곳에 버려진 도시나 건물들이 있다니.","JPN":"こんな無人惑星みたいなところに、捨てられた街や建物があるなんて。","ENG":"This place is like an alien planet, but there are abandoned cities and buildings here.","TWN":"在這種像外星球一樣的地方，竟然會有被遺棄的都市和建築物。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그러고 보니 무슨 음모론 책 같은 것도 있지 않았나?","JPN":"そういえば、なんとか陰謀論の本にもあったじゃないか？","ENG":"Didn't we find a conspiracy book one time?","TWN":"說起來，不是有本像是陰謀論的書嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"프리메이슨이 숨긴 이면세계와 피라미드의 비밀?","JPN":"「フリーメイソンが隠した裏世界とピラミッドの秘密」？","ENG":"The Freemasons' Hidden Counterside and the Secret to the Pyramids?","TWN":"共濟會隱瞞的異界與金字塔隱藏的秘密？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"뭐 대충 그런 제목이었던 거 같은데.","JPN":"だいたいそんなタイトルだったような……","ENG":"Something like that.","TWN":"嗯，大概就是這個書名吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"스승님, 평소에 책도 읽으세요?","JPN":"師匠、本なんて読まれてるんですか？","ENG":"I didn't know you read, Master.","TWN":"師父，妳平常也看書的嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이야, 이건 또 새로운 발견이군요.","JPN":"こりゃまた新しい発見ですね。","ENG":"Well, that's new.","TWN":"哇，又一個新發現耶！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......넌 날 대체 뭐로 생각하는 거냐?","JPN":"……お前、私のことをいったい何だと思ってるんだ？","ENG":"...What kind of person do you think I am?","TWN":"……你到底把我想成什麼樣的人了？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"정말 듣고 싶으세요?","JPN":"本気で聞きたいですか？","ENG":"Do you really wanna know...?","TWN":"妳真的想知道？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L26_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......됐어.","JPN":"……いや、いい。","ENG":"...Forget it.","TWN":"……算了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"브리핑이나 계속해.","JPN":"ブリーフィングを続けろ。","ENG":"Continue the briefing.","TWN":"繼續任務說明吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"수호령께서 말씀하시길,","JPN":"守護霊様の話によると、","ENG":"According to my guardian spirit...","TWN":"守護神說："},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"적 침식 코어는 제 3종 침식체가 파괴된 뒤로 크게 위축되어 있다고 합니다.","JPN":"敵の侵食コアは、第3種の侵食体が破壊されてから、大きく萎縮しているそうです。","ENG":"The enemy's Corruption Core was greatly weakened after the Category 3 C.O. was destroyed.","TWN":"擊破3級侵蝕體後，敵方的侵蝕核心大幅萎縮。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"호위용으로 보이는 하위 침식체 또한 엄청난 숫자로 포진해 있는 것이 확인되었습니다.","JPN":"ガードの下位侵食体も、すさまじい数で広がっていることを確認しました。","ENG":"We've also confirmed that there's a massive army of low-level Corrupted Objects that seem to be guarding the corruption core.","TWN":"並且確認到保護侵蝕核心的低等侵蝕體數量激增。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"아마 지금쯤은 저희의 침입도 눈치챘을 테니, 경계도도 매우 높을 것으로 추정됩니다.","JPN":"すでに私たちの進入にも気づいているはずなので、警戒度も非常に高いとみられます。","ENG":"They probably caught on to our infiltration by now, so they'll definitely be on guard.","TWN":"它們可能已經察覺到我們的入侵，現在警戒度非常高。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"이러한 정황을 종합해 봤을 때.......","JPN":"こうした状況を総合的に考えると……","ENG":"Based on this information...","TWN":"綜合這些情況……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"정면으로 싸우는 것은 위험하다고 판단됩니다.","JPN":"正面から戦うのは危険かと思われます。","ENG":"I believe it would be dangerous to attack head on.","TWN":"我們判斷正面進攻會十分危險。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그럼?","JPN":"というと？","ENG":"Then what?","TWN":"所以？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"당연히 제가 다섯 가지 영험한 마법재료를 모아 제작한 이 수호부를 지참하셔야 합니다.","JPN":"私が効果抜群の魔法素材を5つ集めて製作した、このお守りを持参するのです。","ENG":"You must take this good luck charm that I created using five different magical ingredients!","TWN":"所以當然得帶上這個，由我收集了五種靈驗的魔法材料，製作而成的護身符。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"가격은.......","JPN":"お値段は……","ENG":"The price is...","TWN":"價格的話……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"클로에! 회사에서 그런 거 팔면 안 돼!","JPN":"クロエ！会社でそんなの売っちゃダメでしょ！","ENG":"Chloe! You can't sell things like that at work!","TWN":"克洛伊！不可以在公司賣這種東西！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L41_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"......칫.","JPN":"……ちぇ。","ENG":"Hmph...","TWN":"切。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L42_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"수호령이시여......","JPN":"守護霊様……","ENG":"Oh, guardian spirit...","TWN":"守護神啊……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L43_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"저 불경한 자에게 불면증과 건망증과 소화불량의 저주를 내리소서......","JPN":"あの不敬者に不眠症と物忘れ、消化不良の呪いをかけてください……","ENG":"Will you bestow upon that ungrateful being a curse of insomnia, forgetfulness, and indigestion...","TWN":"請詛咒這個不敬者，讓她得失眠症、健忘症、消化不良……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L46_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"죄송합니다...... 흠흠.","JPN":"申し訳ありません……ごほん。","ENG":"I'm sorry... Ahem.","TWN":"非常抱歉……咳咳。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"작전부의 판단으로는 두 소대가 각각 역할을 나누어 공격하기를 제안드립니다.","JPN":"作戦部からは、両小隊が役割分担をして攻撃をしかけることを提案したいと思います。","ENG":"The recommendation from Operation Department is to assign a different role to each squad.","TWN":"作戰部在判斷情況後，提議讓兩支小隊分工合作，分別發動進攻。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......어떤 식으로?","JPN":"……どんな風に？","ENG":"What roles?","TWN":"……怎麼分？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"망치와 모루로 나눕니다.","JPN":"鎚と金床に分けるのです。","ENG":"A hammer and an anvil.","TWN":"使用錘砧戰術。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"침식 코어는 아마도 제 3종 침식체와 동급의 고위 침식체로 추정됩니다.","JPN":"侵食コアはおそらく、第3種侵食体と同レベルの高位侵食体と推定されます。","ENG":"We estimate that the Corruption Core is equivalent to a Category 3 C.O.","TWN":"經推測，侵蝕核心應該是與3級侵蝕體同等級的高等侵蝕體。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"이런 고위 침식체와 정면으로 싸울 수 있는 펜릴 소대가 망치를,","JPN":"このような高位侵食体と正面対決できるフェンリル小隊が鎚を、","ENG":"Since Fenrir has a proven track record with a Category 3, it'll be the hammer.","TWN":"芬里爾小隊能夠正面對抗這種高等侵蝕體，所以擔任鐵鎚的角色。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"알트 소대가 모루를 맡습니다.","JPN":"アルト小隊が金床を担当します。","ENG":"The ALT Squad will become the anvil.","TWN":"而阿爾特小隊則扮演砧板。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"흐음.......","JPN":"……ふむ。","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"알트소대가 적들을 도발해서 하위 침식체를 유인하여 버티는 동안,","JPN":"アルト小隊が敵を挑発して下位侵食体を\\nおびき寄せる。そうやって時間稼ぎをしている間に、","ENG":"While the ALT Squad lures out the low-ranking Corrupted Objects...","TWN":"在阿爾特小隊挑釁敵方，吸引低等侵蝕體的時候……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"펜릴 소대가 유적지를 우회하여 침식 코어를 격파합니다.","JPN":"フェンリル小隊が遺跡地帯を迂回して侵食コアを撃破します。","ENG":"Fenrir Squad can bypass the ruins and destroy the Corruption Core.","TWN":"芬里爾小隊迂迴到遺跡後方，擊破侵蝕核心。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"그 후에 남은 적을 앞뒤로 포위하여 분쇄합니다.","JPN":"その後、残りの敵を前後ではさんで木っ端みじんにするのです。","ENG":"Afterwards, we can surround the remaining enemies from both sides and crush them.","TWN":"最後兩個小隊從前後包夾剩餘敵人，一舉將它們殲滅。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"와아, 정말 멋진 작전이네요!","JPN":"わあ、本当に見事な作戦ですね！","ENG":"Wow! That's an awesome plan!","TWN":"哇啊，這個作戰好帥喔！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"멋진 건 모르겠지만, 작전부가 제대로 돌아가긴 하는 것 같군.","JPN":"見事かはわからないが、作戦部がまともに機能してはいるようだな。","ENG":"I don't know about \\"awesome\\", but the Operation Department sure seems to know what it's doing.","TWN":"帥不帥不知道，不過作戰部看起來有在正常運作。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그나저나 유인 역할이라니, 알트 소대가 꽤 고생하겠는데.","JPN":"しかし、おびき寄せ役のアルト小隊が大変そうだな。","ENG":"It won't be easy for the ALT Squad to lure them out.","TWN":"但話說回來，阿爾特小隊要吸引敵人應該會很辛苦。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......괜찮은가?","JPN":"……大丈夫か？","ENG":"Are okay with this?","TWN":"你們沒問題吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"저희 같은 신입이야 위에서 시키는 대로 하는 거죠.","JPN":"私みたいな新人は、上から言われたとおりにやるだけですよ。","ENG":"Rookies like us just do what we've been told!","TWN":"我們這樣的新人，當然要服從上層的指示啦。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"이렇게 작전을 같이 하는 것만 해도 배우는 게 많은걸요.","JPN":"こうやって共同作戦ができるだけでも、学べることがたくさんありますからね。","ENG":"We'll be learning so much by doing this mission with you.","TWN":"而且能夠像這樣一起作戰，我們就已經能學到很多啦。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"흐음...... 뭐, 그렇다면야.","JPN":"ふむ……それならいいが。","ENG":"Hmm... If you say so.","TWN":"嗯……好吧，那就好。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이야. 정말 천사 같은 분이시네요, 서윤 양은.","JPN":"いやあ、本当に天使みたいな方ですね、シズカさんは。","ENG":"Wow... You're like an angel, Seo Yoon.","TWN":"哎呀，真的就像天使一樣呢，徐芸小姐。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"스승님이 서윤 양을 절반만 닮았더라도, 펜릴 소대의 악명이 퍼지는 일은 없었을 텐데 말이죠.","JPN":"師匠にこんな心遣いが半分でもできてたら、フェンリル小隊が悪名をとどろかせることはなかったでしょうね。","ENG":"If the Master was half as kind as you, Fenrir Squad would be famous instead of infamous.","TWN":"要是師父能有徐芸小姐的一半，芬里爾小隊就不會這麼惡名昭彰了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......넌 제발 헛소리 좀 그만해.","JPN":"……お前、たわごともいい加減にしろよ。","ENG":"...Would you please stop?","TWN":"……你給我少說點廢話。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L27_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그럼 출발한다.","JPN":"では、出発だ。","ENG":"Let's go.","TWN":"那出發吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"빨리 끝내 버리자고.","JPN":"さっさと片づけるぞ。","ENG":"Let's get this over with.","TWN":"讓我們快點解決掉這件事。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};